def has_cycle_undirected(n, adj):
    visited = [False] * n

    def dfs(u, parent):
        visited[u] = True
        for v in adj.get(u, []):
            if not visited[v]:
                if dfs(v, u):
                    return True
            elif ___________:   # visited but not parent -> cycle
                return True
        return False

    return any(dfs(u, -1) for u in range(n) if not visited[u])
